import java.io.*;
import java.util.*;
public class Main{
    static boolean ok(long[] A,long[] B,long X){
        int n=A.length;int i=0,j=0;boolean skipped=false;
        while(i<n && j<B.length){
            if(A[i]+X==B[j]){i++;j++;}
            else if(!skipped){i++;skipped=true;}
            else return false;
        }
        return true;
    }
    public static void main(String[] args) throws Exception{
        FastScanner fs=new FastScanner(System.in);
        int T=fs.nextInt();
        StringBuilder sb=new StringBuilder();
        while(T-- >0){
            int N=fs.nextInt();
            long[] A=new long[N];
            long[] B=new long[N-1];
            for(int i=0;i<N;i++) A[i]=fs.nextLong();
            for(int i=0;i<N-1;i++) B[i]=fs.nextLong();
            Arrays.sort(A);
            Arrays.sort(B);
            long ans=Long.MAX_VALUE;
            long[] cand={B[0]-A[0], B[0]-A[1]};
            for(long X:cand){
                if(X>0 && ok(A,B,X)) ans=Math.min(ans,X);
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
    static class FastScanner{
        private final InputStream in;private final byte[] buffer=new byte[1<<16];private int ptr=0, len=0;
        FastScanner(InputStream is){in=is;}
        private int readByte() throws IOException{if(ptr>=len){len=in.read(buffer);ptr=0;if(len<=0) return -1;}return buffer[ptr++];}
        long nextLong() throws IOException{int c; do{c=readByte();}while(c<=32); boolean neg=false; if(c=='-'){neg=true;c=readByte();}
            long val=0; while(c>32){val=val*10+(c-'0');c=readByte();}
            return neg?-val:val;}
        int nextInt() throws IOException{return (int)nextLong();}
    }
}

