import sys

def ok(A,B,X):
    i=j=0
    skipped=False
    n=len(A)
    m=len(B)
    while i<n and j<m:
        if A[i]+X==B[j]:
            i+=1;j+=1
        elif not skipped:
            i+=1;skipped=True
        else:
            return False
    return True

def solve():
    data=list(map(int,sys.stdin.read().split()))
    it=iter(data)
    T=next(it)
    out=[]
    for _ in range(T):
        N=next(it)
        A=[next(it) for _ in range(N)]
        B=[next(it) for _ in range(N-1)]
        A.sort();B.sort()
        ans=10**20
        cand=[B[0]-A[0], B[0]-A[1]]
        for X in cand:
            if X>0 and ok(A,B,X):
                ans=min(ans,X)
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))
if __name__=='__main__':
    solve()

